#include<bits/stdc++.h>
using namespace std;
int a[1005][1005],b[1005][1005],n,m,cnt=1; 
double s[1005];
vector<int> x,y;
int main(void){
	cin>>m>>n;
	for(int i=1;i<=n;i++)
		for(int j=1;j<=m;j++)
			cin>>a[i][j];
	for(int i=1;i<=n;i++)
		for(int j=1;j<=m;j++)
			cin>>b[i][j];
	for(int i=1;i<=n;i++){
		
		double avg=0;
		for(int k=1;k<=m;k++){
			avg+=a[i][k]*1.0;
		}avg/=m*1.0;
		double s1=0.0;
		for(int j=1;j<=m;j++){
			s1+=(a[i][j]*1.0-avg)*(a[i][j]*1.0-avg);
		}s1/=m*1.0;s[i]+=s1*1.0;
		avg=0;
		for(int k=1;k<=m;k++){
			avg+=b[i][k]*1.0;
		}avg/=m;
		double s2=0.0;
		for(int j=1;j<=m;j++){
			s2+=(b[i][j]*1.0-avg)*(b[i][j]*1.0-avg);
		}s2/=m*1.0;s[i]+=s2*1.0;
	}
	for(int i=1;i<=n;i++){
		for(int j=1;j<i;j++){
			if(s[j]>s[i]){
				x.push_back(i);
				y.push_back(j);
				swap(s[i],s[j]);
			}
		}
	}
	cout<<y.size()<<'\n';
	for(int i=0;i<x.size();i++){
		cout<<x[i]<<' '<<y[i]<<'\n';
	}
	return false;
}
